const raw = $('List Input Files').first().json.stdout || '';

const supportedExts = ['.fbx','.usd','.usda','.usdc','.abc','.blend','.obj','.gltf','.glb'];
const parts = raw.split('---PDF---');
const cadLines = parts[0].split('\n').map(f => f.trim()).filter(f => f.length > 0);
const pdfLines = (parts[1] || '').split('\n').map(f => f.trim()).filter(f => f.length > 0);

function getExt(f) { return f.slice(f.lastIndexOf('.')).toLowerCase(); }
function getBase(f) { return f.slice(0, f.lastIndexOf('.')).toLowerCase(); }

const cadFiles = cadLines.filter(f => supportedExts.includes(getExt(f)));
const pdfFiles = pdfLines.filter(f => getExt(f) === '.pdf');

let match = null;
for (const cad of cadFiles) {
  const cadBase = getBase(cad);
  const pdf = pdfFiles.find(p => getBase(p) === cadBase);
  if (pdf) {
    match = { pairFound: true, baseName: cadBase, cadFile: cad, pdfFile: pdf };
    break;
  }
}

return [{ json: match ?? { pairFound: false, baseName: null, cadFile: null, pdfFile: null } }];

const now = new Date();
const pad = n => String(n).padStart(2,'0');
const ts = `${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}_${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;
const baseName = $input.first().json.baseName;
const jobId = `${baseName}_${ts}`;
return[
  {
    json:
    {
      ...$input.first().json,
      jobId,
      intermediatesDir: `C:\\pipeline\\intermediates\\${jobId}`,
      outputsDir: `C:\\pipeline\\outputs`,
      logsDir: `C:\\pipeline\\logs`
    }
  }
];

